import { z } from "zod";

const registrationSchema = z.object({
  username: z.string().min(3, "Username must be at least 3 characters"),
  email: z.string().email("Invalid email address"),
  role: z.enum(["user", "admin", "contributor"]),
  otherInfo: z.string().optional(),
  newsletter: z.boolean().optional(),
  frequency: z.string().optional(),
  bio: z.string().optional(),
}).superRefine((data, ctx) => {
  // otherInfo required when role === "contributor"
  if (data.role === "contributor" && !data.otherInfo) {
    ctx.addIssue({
      code: z.ZodIssueCode.custom,
      message: "otherInfo is required for contributors",
      path: ["otherInfo"],
    });
  }

  // frequency required when newsletter is true
  if (data.newsletter === true && !data.frequency) {
    ctx.addIssue({
      code: z.ZodIssueCode.custom,
      message: "frequency is required when newsletter is subscribed",
      path: ["frequency"],
    });
  }
});

type RegistrationFormValues = z.infer<typeof registrationSchema>;

export type { registrationSchema, RegistrationFormValues };

