// Role options for the role radio group
export const roleOptions = ["user", "admin", "contributor"] as const;

// Frequency options for the newsletter frequency radio group
export const frequencyOptions = ["daily", "weekly", "monthly"] as const;

// Base schema for common optional fields
const baseOptional = z.object({
  newsletter: z.boolean().optional(),
  bio: z.string().optional(),
});

// Schema for contributor-specific otherInfo field
const contributorInfoSchema = z.object({
  otherInfo: z.string().optional(),
});

// Main schema with conditional validation via superRefine
const registrationSchema = baseOptional.and(contributorInfoSchema).superRefine(
  (data, ctx) => {
    // otherInfo is required when role === "contributor"
    if (data.role === "contributor" && !data.otherInfo) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Other info is required for contributors",
        path: ["otherInfo"],
      });
    }

    // frequency is required when newsletter === true
    if (data.newsletter === true && !data.frequency) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Please select a frequency when subscribed to the newsletter",
        path: ["frequency"],
      });
    }
  }
);

export { registrationSchema };

// TypeScript type inferred from the schema
type RegistrationFormValues = z.infer<typeof registrationSchema>;

// Options arrays for component usage
export type RoleOption = (typeof roleOptions)[number];
export type FrequencyOption = (typeof frequencyOptions)[number];

